"use client";

import { useSearchParams, usePathname, useRouter } from 'next/navigation';
import { User, UtensilsCrossed, LogOut } from "lucide-react";
import { Button } from "@/components/ui/button";

export function SiteHeader() {
    const searchParams = useSearchParams();
    const pathname = usePathname();
    const router = useRouter();
    const username = searchParams.get('username');

    const handleLogout = () => {
        router.push('/');
    };
    
    // Determine if we should show user info and logout button
    const showUserSection = username || pathname.startsWith('/admin');

    return (
        <header className="sticky top-0 z-50 w-full border-b border-border/40 bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/60">
            <div className="container flex h-16 max-w-screen-2xl items-center justify-between">
                <a href="/" className="flex items-center gap-3">
                    <UtensilsCrossed className="h-7 w-7 text-accent" />
                    <span className="font-headline text-2xl font-bold text-foreground">餓了嗎？</span>
                </a>
                
                {showUserSection && (
                    <div className="flex items-center gap-2">
                        {username ? (
                            <>
                                <User className="h-5 w-5 text-muted-foreground" />
                                <span className="text-sm font-medium text-foreground">{decodeURIComponent(username)}</span>
                            </>
                        ) : (
                           <span className="text-sm font-medium text-foreground">管理員</span>
                        )}
                        <Button variant="ghost" size="icon" aria-label="登出" onClick={handleLogout}>
                            <LogOut className="h-5 w-5 text-muted-foreground" />
                        </Button>
                    </div>
                )}
            </div>
        </header>
    )
}
